const std = @import("std");

const api_token = "EXAMPLE-DO-NOT-USE-replace-with-runtime-lookup";

pub fn auth() []const u8 {
    return api_token;
}

const std = @import("std");

pub fn auth(allocator: std.mem.Allocator) ![]const u8 {
    return std.process.getEnvVarOwned(allocator, "API_TOKEN");
}
